import React , { useState }  from "react";
import logo from "./images/logo.png";
import Container from 'react-bootstrap/Container';
import Nav from 'react-bootstrap/Nav';
import Navbar from 'react-bootstrap/Navbar';
import "./Home.css";
import Button from 'react-bootstrap/Button';
import Form from 'react-bootstrap/Form';
import { useNavigate ,Link } from 'react-router-dom';

function Register() {
  const navigate = useNavigate();
  const [data, setData] = useState({
    name: "",
    username: "",
    pin: "",
    parentContact: "",
  });

  const [contract, setContract] = useState(false);

  const handleContract = () => {
    setContract(!contract);
  };

  const handleInputChange = (event) => {
    const { name, value } = event.target;
    setData((prevFormData) => ({
      ...prevFormData,
      [name]: value,
    }));
  };

  const handleSubmit = async (event) => {
    event.preventDefault();

    const { name, username, pin, parentContact } = data;

    if (!name || !username || !pin) {
      alert("Please fill in all required fields (name, username, pin)");
      return;
    }

    if (!parentContact) {
      alert("Please enter a parent contact number or email.");
      return;
    }

    const formData = new FormData();
    formData.append("name", name);
    formData.append("username", username);
    formData.append("pin", pin);
    formData.append("parentContact", parentContact);

    try {
      const response = await fetch("http://localhost:5000/api/register", {
        method: "POST",
        body: formData,
      });

      const result = await response.json();

      if (response.ok) {
        alert("You have been successfully registered!");
        navigate("/dashboard");
      } else {
        alert(result.message || "Failed to register");
      }
    } catch (error) {
      console.error("Error submitting data:", error);
      alert("Error occurred while registering");
    }
  };

  return (
    <div className="subs">
      <Navbar bg="light" variant="light" expand="lg">
        <Container>
          <Navbar.Brand href="/">
            <img src={logo} width="30" height="30" alt="Logo" />
          </Navbar.Brand>
          <Navbar.Toggle aria-controls="basic-navbar-nav" />
          <Navbar.Collapse id="basic-navbar-nav">
            <Nav className="me-auto">
              <Nav.Link as={Link} to="/contact">Contacts</Nav.Link>
              <Nav.Link as={Link} to="/">Home</Nav.Link>
              <Nav.Link as={Link} to="/login">Login</Nav.Link>
            </Nav>
          </Navbar.Collapse>
        </Container>
      </Navbar>

      <h1>Register to Play!</h1>

      <Form onSubmit={handleSubmit}>
        <Form.Group className="mb-3 input">
          <Form.Label>First Name</Form.Label>
          <Form.Control
            type="text"
            name="name"
            value={data.name}
            onChange={handleInputChange}
            placeholder="Enter your name"
          />
        </Form.Group>

        <Form.Group className="mb-3 input">
          <Form.Label>Username</Form.Label>
          <Form.Control
            type="text"
            name="username"
            value={data.username}
            onChange={handleInputChange}
            placeholder="Pick a fun username!"
          />
        </Form.Group>

        <Form.Group className="mb-3 input">
          <Form.Label>4-digit PIN</Form.Label>
          <Form.Control
            type="password"
            name="pin"
            value={data.pin}
            maxLength="4"
            pattern="\d{4}"
            onChange={handleInputChange}
            placeholder="Enter a 4-digit PIN"
          />
        </Form.Group>

        <Form.Group className="mb-3 input">
          <Form.Label>Parent Contact (Email or Phone)</Form.Label>
          <Form.Control
            type="text"
            name="parentContact"
            value={data.parentContact}
            onChange={handleInputChange}
            placeholder="Enter parent's contact"
          />
        </Form.Group>

        <h5>Legal Stuff</h5>
        <Form.Text className="text-muted">
          We only use this info to save your progress and help you become a better speller! 🎉 No spam, no sharing data.
        </Form.Text>

        <Form.Group className="mt-3">
          <label>
            <input type="checkbox" checked={contract} onChange={handleContract} />
            I agree to the terms and conditions
          </label>
        </Form.Group>

        <Button variant="primary" type="submit" hidden={!contract}>
          Submit
        </Button>
      </Form>
    </div>
  );
}

export default Register;
